// Current time in milliseconds
const now = new Date();

// 24 hours ago
const cutoff = new Date(now.getTime() - 24 * 60 * 60 * 1000);

// Access the video list from the previous node
const items = $input.first().json.items || [];

const filtered = items.filter(item => {
  const publishedAt = item.snippet?.publishedAt || '';
  if (!publishedAt) return false;

  const pubDate = new Date(publishedAt);

  // Keep video if it was published within the last 24 hours
  return pubDate >= cutoff && pubDate <= now;
});

// Return each video as a separate item for the next node
return filtered.map(item => ({
  json: {
    videoId: item.snippet.resourceId.videoId,
    title: item.snippet.title,
    publishedAt: item.snippet.publishedAt,
    url: `https://www.youtube.com/watch?v=${item.snippet.resourceId.videoId}`
  }
}));

// "Merge Transcripts" — runs once
const transcripts = $input.all();                  // [{ text }, ...] in order
const videos = $("Filter Today's Videos").all();   // [{ title, url, ... }, ...]

const docs = [];
let merged = '';

for (let i = 0; i < transcripts.length; i++) {
  const text = (transcripts[i].json.text || '').trim();
  const title = videos[i]?.json.title || `Video ${i + 1}`;
  const url = videos[i]?.json.url || '';
  if (!text) continue;
  docs.push({ title, url, transcript: text });
  merged += "\n\n" + "TITLE OF VIDEO: " + title + "\ntranscript: " + text
}

return [{
  json: {
    transcript_merge: merged,
    videos: docs,                 // structured array, if you prefer JSON downstream
    videoCount: docs.length,
    generatedAt: new Date().toISOString(),
  },
}];

